study:
// Standard MGnify study fetch hook
import useSWR from 'swr';
import { fetcher } from '@/utils/api';

export function useStudy(accession) {
  const { data, error, isLoading } = useSWR(
    accession ? `/studies/${accession}` : null,
    fetcher
  );
  return {
    study: data?.data?.attributes,
    accession: data?.data?.id,
    isLoading,
    error,
  };
}

studies:
// Standard MGnify studies list hook with cursor pagination
import useSWR from 'swr';
import { useState } from 'react';
import { fetcher } from '@/utils/api';

export function useStudies() {
  const [pageUrl, setPageUrl] = useState('/studies');
  const { data, error, isLoading } = useSWR(pageUrl, fetcher);
  return {
    studies: data?.data ?? [],
    isLoading,
    error,
    hasNext: !!data?.links?.next,
    hasPrev: !!data?.links?.prev,
    goNext: () => data?.links?.next && setPageUrl(data.links.next),
    goPrev: () => data?.links?.prev && setPageUrl(data.links.prev),
  };
}

